class Solution:
    def numSplits(self, s):
        freq = {}
        for ch in s:
            freq[ch] = freq.get(ch, 0) + 1
        distinct_right = len(freq)
        left_seen = {}
        ans = 0
        for i in range(len(s) - 1):
            ch = s[i]
            if left_seen.get(ch, 0) == 0:
                left_seen[ch] = 1
            else:
                left_seen[ch] += 1
            freq[ch] -= 1
            if freq[ch] == 0:
                distinct_right -= 1
            if len(left_seen) == distinct_right:
                ans += 1
        return ans

