var numSplits = function(s) {
    const freq = new Map();
    for (const ch of s) freq.set(ch, (freq.get(ch) || 0) + 1);
    let distinctRight = freq.size;
    const leftSeen = new Map();
    let ans = 0;
    for (let i = 0; i < s.length - 1; i++) {
        const ch = s[i];
        leftSeen.set(ch, (leftSeen.get(ch) || 0) + 1);
        freq.set(ch, freq.get(ch) - 1);
        if (freq.get(ch) === 0) distinctRight -= 1;
        if (leftSeen.size === distinctRight) ans += 1;
    }
    return ans;
};
